from __future__ import annotations
from dataclasses import dataclass


@dataclass(frozen=True)
class ProviderTier:
    name: str
    rpm: int       # requests per minute
    tpm: int       # tokens per minute
    rpd: int       # requests per day
    monthly_cost_usd: float


ANTHROPIC_TIERS: list[ProviderTier] = [
    ProviderTier("Tier 1",    50,     40_000,    1_000,   0.0),
    ProviderTier("Tier 2",   1000,   160_000,   10_000,   0.0),
    ProviderTier("Tier 3",   2000,   400_000,   100_000,  0.0),
    ProviderTier("Tier 4",   4000,   800_000,   500_000,  0.0),
    ProviderTier("Tier 5", 10_000, 2_000_000, 2_000_000, 0.0),
]


@dataclass
class WorkloadProfile:
    peak_concurrent_users: int
    avg_requests_per_user_per_minute: float
    avg_tokens_per_request: int
    daily_active_users: int
    avg_requests_per_user_per_day: float

    @property
    def peak_rpm(self) -> float:
        return self.peak_concurrent_users * self.avg_requests_per_user_per_minute

    @property
    def peak_tpm(self) -> float:
        return self.peak_rpm * self.avg_tokens_per_request

    @property
    def peak_rpd(self) -> float:
        return self.daily_active_users * self.avg_requests_per_user_per_day


class RateLimitCalculator:
    def __init__(self, tiers: list[ProviderTier], safety_factor: float = 1.30):
        self.tiers = sorted(tiers, key=lambda t: t.rpm)
        self.safety_factor = safety_factor

    def required_capacity(self, profile: WorkloadProfile) -> dict:
        required_rpm = profile.peak_rpm * self.safety_factor
        required_tpm = profile.peak_tpm * self.safety_factor
        required_rpd = profile.peak_rpd * self.safety_factor
        return {
            "required_rpm": required_rpm,
            "required_tpm": required_tpm,
            "required_rpd": required_rpd,
        }

    def recommend_tier(self, profile: WorkloadProfile) -> dict:
        caps = self.required_capacity(profile)
        for tier in self.tiers:
            if (
                tier.rpm >= caps["required_rpm"]
                and tier.tpm >= caps["required_tpm"]
                and tier.rpd >= caps["required_rpd"]
            ):
                headroom = {
                    "rpm_pct": round((tier.rpm / caps["required_rpm"] - 1) * 100, 1),
                    "tpm_pct": round((tier.tpm / caps["required_tpm"] - 1) * 100, 1),
                    "rpd_pct": round((tier.rpd / caps["required_rpd"] - 1) * 100, 1),
                }
                return {
                    "recommended_tier": tier.name,
                    "headroom_pct": headroom,
                    "bottleneck": min(headroom, key=headroom.get),
                    "capacity": caps,
                }
        return {"recommended_tier": "Beyond Tier 5 — negotiate custom limits", "capacity": caps}


if __name__ == "__main__":
    profile = WorkloadProfile(
        peak_concurrent_users=200,
        avg_requests_per_user_per_minute=0.5,
        avg_tokens_per_request=2_000,
        daily_active_users=1_500,
        avg_requests_per_user_per_day=30,
    )
    calc = RateLimitCalculator(ANTHROPIC_TIERS, safety_factor=1.30)
    result = calc.recommend_tier(profile)
    print(f"Recommended: {result['recommended_tier']}")
    print(f"Bottleneck dimension: {result['bottleneck']}")
    for dim, pct in result['headroom_pct'].items():
        print(f"  {dim} headroom: {pct}%")
